+-my $Is_VMS = $^O eq 'VMS';
+-my $Is_MacOS = $^O eq 'MacOS';
++Gisle Aas made a number of improvements to the documentation for
++2.07 and his advice and assistance is also greatly appreciated.
+ 
+-# These OSes complain if you want to remove a file that you have no
+-# write permission to:
+-my $force_writeable = ($^O eq 'os2' || $^O eq 'dos' || $^O eq 'MSWin32' ||
+-		       $^O eq 'amigaos' || $^O eq 'MacOS' || $^O eq 'epoc');
++=head1 AUTHORS
+ 
+-sub mkpath {
+-    my($paths, $verbose, $mode) = @_;
+-    # $paths   -- either a path string or ref to list of paths
+-    # $verbose -- optional print "mkdir $path" for each directory created
+-    # $mode    -- optional permissions, defaults to 0777
+-    local($")=$Is_MacOS ? ":" : "/";
+-    $mode = 0777 unless defined($mode);
+-    $paths = [$paths] unless ref $paths;
+-    my(@created,$path);
+-    foreach $path (@$paths) {
+-	$path .= '/' if $^O eq 'os2' and $path =~ /^\w:\z/s; # feature of CRT 
+-	# Logic wants Unix paths, so go with the flow.
+-	if ($Is_VMS) {
+-	    next if $path eq '/';
+-	    $path = VMS::Filespec::unixify($path);
+-	    if ($path =~ m:^(/[^/]+)/?\z:) {
+-	        $path = $1.'/000000';
+-	    }
+-	}
+-	next if -d $path;
+-	my $parent = File::Basename::dirname($path);
+-	unless (-d $parent or $path eq $parent) {
+-	    push(@created,mkpath($parent, $verbose, $mode));
+- 	}
+-	print "mkdir $path\n" if $verbose;
+-	unless (mkdir($path,$mode)) {
+-	    my $e = $!;
+-	    # allow for another process to have created it meanwhile
+-	    $! = $e, croak ("mkdir $path: $e") unless -d $path;
+-	}
+-	push(@created, $path);
+-    }
+-    @created;
+-}
++Tim Bunce and Charles Bailey. Currently maintained by David Landgren
++<F<david@landgren.net>>.
+ 
+-sub rmtree {
+-    my($roots, $verbose, $safe) = @_;
+-    my(@files);
+-    my($count) = 0;
+-    $verbose ||= 0;
+-    $safe ||= 0;
+-
+-    if ( defined($roots) && length($roots) ) {
+-      $roots = [$roots] unless ref $roots;
+-    }
+-    else {
+-      carp "No root path(s) specified\n";
+-      return 0;
+-    }
++=head1 COPYRIGHT
+ 
+-    my($root);
+-    foreach $root (@{$roots}) {
+-    	if ($Is_MacOS) {
+-	    $root = ":$root" if $root !~ /:/;
+-	    $root =~ s#([^:])\z#$1:#;
+-	} else {
+-	    $root =~ s#/\z##;
+-	}
+-	(undef, undef, my $rp) = lstat $root or next;
+-	$rp &= 07777;	# don't forget setuid, setgid, sticky bits
+-	if ( -d _ ) {
+-	    # notabene: 0700 is for making readable in the first place,
+-	    # it's also intended to change it to writable in case we have
+-	    # to recurse in which case we are better than rm -rf for 
+-	    # subtrees with strange permissions
+-	    chmod($rp | 0700, ($Is_VMS ? VMS::Filespec::fileify($root) : $root))
+-	      or carp "Can't make directory $root read+writeable: $!"
+-		unless $safe;
+-
+-	    if (opendir my $d, $root) {
+-		no strict 'refs';
+-		if (!defined ${"\cTAINT"} or ${"\cTAINT"}) {
+-		    # Blindly untaint dir names
+-		    @files = map { /^(.*)$/s ; $1 } readdir $d;
+-		} else {
+-		    @files = readdir $d;
+-		}
+-		closedir $d;
+-	    }
+-	    else {
+-	        carp "Can't read $root: $!";
+-		@files = ();
+-	    }
+-
+-	    # Deleting large numbers of files from VMS Files-11 filesystems
+-	    # is faster if done in reverse ASCIIbetical order 
+-	    @files = reverse @files if $Is_VMS;
+-	    ($root = VMS::Filespec::unixify($root)) =~ s#\.dir\z## if $Is_VMS;
+-	    if ($Is_MacOS) {
+-		@files = map("$root$_", @files);
+-	    } else {
+-		@files = map("$root/$_", grep $_!~/^\.{1,2}\z/s,@files);
+-	    }
+-	    $count += rmtree(\@files,$verbose,$safe);
+-	    if ($safe &&
+-		($Is_VMS ? !&VMS::Filespec::candelete($root) : !-w $root)) {
+-		print "skipped $root\n" if $verbose;
+-		next;
+-	    }
+-	    chmod $rp | 0700, $root
+-	      or carp "Can't make directory $root writeable: $!"
+-		if $force_writeable;
+-	    print "rmdir $root\n" if $verbose;
+-	    if (rmdir $root) {
+-		++$count;
+-	    }
+-	    else {
+-		carp "Can't remove directory $root: $!";
+-		chmod($rp, ($Is_VMS ? VMS::Filespec::fileify($root) : $root))
+-		    or carp("and can't restore permissions to "
+-		            . sprintf("0%o",$rp) . "\n");
+-	    }
+-	}
+-	else { 
+-	    if ($safe &&
+-		($Is_VMS ? !&VMS::Filespec::candelete($root)
+-		         : !(-l $root || -w $root)))
+-	    {
+-		print "skipped $root\n" if $verbose;
+-		next;
+-	    }
+-	    chmod $rp | 0600, $root
+-	      or carp "Can't make file $root writeable: $!"
+-		if $force_writeable;
+-	    print "unlink $root\n" if $verbose;
+-	    # delete all versions under VMS
+-	    for (;;) {
+-		unless (unlink $root) {
+-		    carp "Can't unlink file $root: $!";
+-		    if ($force_writeable) {
+-			chmod $rp, $root
+-			    or carp("and can't restore permissions to "
+-			            . sprintf("0%o",$rp) . "\n");
+-		    }
+-		    last;
+-		}
+-		++$count;
+-		last unless $Is_VMS && lstat $root;
+-	    }
+-	}
+-    }
++This module is copyright (C) Charles Bailey, Tim Bunce and
++David Landgren 1995-2008. All rights reserved.
+ 
+-    $count;
+-}
